  1→package agent
  2→
  3→import (
  4→	"context"
  5→	"encoding/json"
  6→	"fmt"
  7→
  8→	"github.com/patflynn/reel-life/internal/sonarr"
  9→)
 10→
 11→func (a *Agent) dispatchSonarr(ctx context.Context, name string, rawInput json.RawMessage) (string, bool, bool) {
 12→	if a.sonarr == nil {
 13→		switch name {
 14→		case "search_series", "add_series", "get_queue", "get_history", "check_health", "remove_failed",
 15→			"get_series_detail", "get_episodes", "get_logs", "manual_search", "get_quality_profiles",
 16→			"get_blocklist", "get_root_folders", "get_download_clients", "update_series_monitoring",
 17→			"trigger_series_search", "delete_series", "remove_blocklist_item", "grab_release",
 18→			"update_episode_monitoring", "monitor_season_episodes":
 19→			return jsonError("Sonarr integration is not configured"), true, true
 20→		}
 21→	}
 22→
 23→	var result any
 24→	var err error
 25→
 26→	switch name {
 27→	case "search_series":
 28→		var input searchSeriesInput
 29→		if err := json.Unmarshal(rawInput, &input); err != nil {
 30→			return jsonError("invalid input: " + err.Error()), true, true
 31→		}
 32→		result, err = a.sonarr.Search(ctx, input.Term)
 33→
 34→	case "add_series":
 35→		var input addSeriesInput
 36→		if err := json.Unmarshal(rawInput, &input); err != nil {
 37→			return jsonError("invalid input: " + err.Error()), true, true
 38→		}
 39→		result, err = a.sonarr.Add(ctx, sonarr.AddSeriesRequest{
 40→			Title:            input.Title,
 41→			TVDBID:           input.TVDBID,
 42→			QualityProfileID: input.QualityProfileID,
 43→			RootFolderPath:   input.RootFolderPath,
 44→			Monitored:        true,
 45→			SeasonFolder:     true,
 46→		})
 47→
 48→	case "get_queue":
 49→		result, err = a.sonarr.Queue(ctx)
 50→
 51→	case "get_history":
 52→		var input getHistoryInput
 53→		if err := json.Unmarshal(rawInput, &input); err != nil {
 54→			return jsonError("invalid input: " + err.Error()), true, true
 55→		}
 56→		pageSize := input.PageSize
 57→		if pageSize == 0 {
 58→			pageSize = 20
 59→		}
 60→		result, err = a.sonarr.History(ctx, pageSize)
 61→
 62→	case "check_health":
 63→		result, err = a.sonarr.Health(ctx)
 64→
 65→	case "remove_failed":
 66→		var input removeFailedInput
 67→		if err := json.Unmarshal(rawInput, &input); err != nil {
 68→			return jsonError("invalid input: " + err.Error()), true, true
 69→		}
 70→		err = a.sonarr.RemoveFailed(ctx, input.ID, input.Blocklist)
 71→		if err == nil {
 72→			result = map[string]string{"status": "removed"}
 73→		}
 74→
 75→	case "get_series_detail":
 76→		var input getSeriesDetailInput
 77→		if err := json.Unmarshal(rawInput, &input); err != nil {
 78→			return jsonError("invalid input: " + err.Error()), true, true
 79→		}
 80→		result, err = a.sonarr.GetSeries(ctx, input.SeriesID)
 81→
 82→	case "get_episodes":
 83→		var input getEpisodesInput
 84→		if err := json.Unmarshal(rawInput, &input); err != nil {
 85→			return jsonError("invalid input: " + err.Error()), true, true
 86→		}
 87→		result, err = a.sonarr.GetEpisodes(ctx, input.SeriesID)
 88→
 89→	case "get_logs":
 90→		var input getLogsInput
 91→		if err := json.Unmarshal(rawInput, &input); err != nil {
 92→			return jsonError("invalid input: " + err.Error()), true, true
 93→		}
 94→		result, err = a.sonarr.GetLogs(ctx, input.PageSize, input.Level)
 95→
 96→	case "manual_search":
 97→		var input manualSearchInput
 98→		if err := json.Unmarshal(rawInput, &input); err != nil {
 99→			return jsonError("invalid input: " + err.Error()), true, true
100→		}
101→		result, err = a.sonarr.ManualSearch(ctx, input.EpisodeID)
102→
103→	case "get_quality_profiles":
104→		result, err = a.sonarr.GetQualityProfiles(ctx)
105→
106→	case "get_blocklist":
107→		var input getBlocklistInput
